import { isArray } from 'lodash-es';
import type { ChangeEvent, Dispatch } from 'react';
import { FormattedMessage } from 'react-intl';

import type { FilterSegment } from '@dynatrace-sdk/client-query';

import type { SegmentSelectorUIState } from './SegmentsUIReducer.js';
import {
  type FormFieldMessagesReducerAction,
  FormFieldMessagesAction,
} from '../../../../forms/forms-core/state/formfield-messages-state-reducer.js';
import type { FormFieldMessageContextState } from '../../../../forms/forms-core/types/formfield-messages.types.js';
import { SEGMENTSELECTOR_MESSAGES } from '../../segmentMessages.js';
import {
  getSegment,
  segmentsClient,
  type CachedSegment,
} from '../SegmentsCache/SegmentsCache.js';

/** @internal */
export async function getErrorKey(
  uiSegment:
    | (FilterSegment | CachedSegment['segment']) & {
        isPlaceholder?: boolean;
        errorKey?: 'unavailable' | 'needs-variables' | 'needs-update';
      },
): Promise<'unavailable' | 'needs-update' | 'needs-variables' | null> {
  if ('isPlaceholder' in uiSegment && uiSegment.isPlaceholder) {
    return null;
  }

  const cachedSegment = await segmentsClient.queryClient.fetchQuery({
    queryKey: ['getSegment', uiSegment.id],
    queryFn: () => getSegment(uiSegment.id).catch(() => null),
  });

  if (!cachedSegment) {
    return 'unavailable';
  }

  const uiSegmentHasNoVariables =
    uiSegment.variables === undefined ||
    (isArray(uiSegment.variables) && uiSegment.variables.length === 0);
  const cachedSegmentHasNoVariables = !cachedSegment.segment.variables;

  if (!cachedSegmentHasNoVariables && uiSegmentHasNoVariables) {
    return 'needs-variables';
  }

  if (!uiSegmentHasNoVariables && cachedSegmentHasNoVariables) {
    return 'needs-update';
  }

  return null;
}

/**
 * Helper function that checks every segment for errors and returns a boolean indicating
 * whether the segments are valid or not.
 * If the user has no access rights, it returns undefined.
 * @internal
 */
export async function areUiSegmentsValid(
  uiSegments?: SegmentSelectorUIState['uiSegments'],
): Promise<boolean | undefined> {
  if (segmentsClient.hasAccessRights === false || !uiSegments) {
    return undefined;
  }

  let hasError = false;

  await Promise.all(
    uiSegments?.map(async (uiSegment) => {
      const errorKey = await getErrorKey(uiSegment);

      if (errorKey) {
        hasError = true;
      }

      return errorKey;
    }),
  );

  return !hasError;
}

/**
 * Iterates over selected segments and checks their availability.
 * If they are no longer available it adds an error.
 * Similarly it removes the error if it no longer applies.
 */
export async function validateSegments(
  segments: FilterSegment[],
  onChange: (
    event?: ChangeEvent<
      HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement
    >,
  ) => void,
  formFieldMessagesDispatch:
    | Dispatch<FormFieldMessagesReducerAction>
    | undefined,
  formControlMessages: FormFieldMessageContextState['formControlMessages'],
  errorId: string,
  showError: boolean = false,
) {
  onChange();
  const isValid = await areUiSegmentsValid(segments);
  const hasFormControlError = formControlMessages.some(
    (message) => message.id === errorId,
  );

  if (
    hasFormControlError &&
    ((segmentsClient.hasAccessRights === false && segments.length === 0) ||
      isValid)
  ) {
    formFieldMessagesDispatch?.({
      type: FormFieldMessagesAction.REMOVEMESSAGE,
      payload: {
        id: errorId,
        messageType: 'formcontrol',
      },
    });

    return;
  }

  if (segmentsClient.hasAccessRights === false && segments.length > 0) {
    formFieldMessagesDispatch?.({
      type: FormFieldMessagesAction.ADDMESSAGE,
      payload: {
        id: errorId,
        variant: 'error',
        validityStateKey: 'customError',
        messageType: 'formcontrol',
        showError: true,
        message: (
          <FormattedMessage
            {...SEGMENTSELECTOR_MESSAGES.noReadAndWriteAccess}
          />
        ),
      },
    });
  }

  if (isValid === false && !hasFormControlError) {
    formFieldMessagesDispatch?.({
      type: FormFieldMessagesAction.ADDMESSAGE,
      payload: {
        id: errorId,
        variant: 'error',
        validityStateKey: 'customError',
        messageType: 'formcontrol',
        showError,
        message: (
          <FormattedMessage {...SEGMENTSELECTOR_MESSAGES.genericSegmentError} />
        ),
      },
    });
  }
}
